diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 28d7e1ce401e..3162b9c300cf 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -3019,10 +3019,13 @@ static bool isKnownNonZeroFromOperator(const Operator *I,
     // (X | (X != 0)) is non zero
     if (matchOpWithOpEqZero(I->getOperand(0), I->getOperand(1)))
       return true;
+    // X | Y != 0 if X != Y.
+    if (isKnownNonEqual(I->getOperand(0), I->getOperand(1), DemandedElts,
+                        Depth, Q))
+      return true;
     // X | Y != 0 if X != 0 or Y != 0.
     return isKnownNonZero(I->getOperand(1), DemandedElts, Q, Depth) ||
            isKnownNonZero(I->getOperand(0), DemandedElts, Q, Depth);
-  case Instruction::SExt:
   case Instruction::ZExt:
     // ext X != 0 if X != 0.
     return isKnownNonZero(I->getOperand(0), DemandedElts, Q, Depth);
@@ -9534,6 +9537,16 @@ isImpliedCondICmps(const ICmpInst *LHS, CmpPredicate RPred, const Value *R0,
   if (auto P = CmpPredicate::getMatching(LPred, RPred))
     return isImpliedCondOperands(*P, L0, L1, R0, R1);

+  // X != Y implies (X | Y) != 0, i.e., (X | Y) == 0 is false.
+  if (LPred == ICmpInst::ICMP_NE &&
+      match(R0, m_c_Or(m_Specific(L0), m_Specific(L1))) &&
+      match(R1, m_Zero())) {
+    if (RPred == ICmpInst::ICMP_EQ)
+      return false;
+    if (RPred == ICmpInst::ICMP_NE)
+      return true;
+  }
+
   return std::nullopt;
 }

